import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Często zadawane pytania dla graczy","description":"Często zadawane pytania dla graczy i administratorów serwerów dotyczące Fabric.","frontmatter":{"title":"Często zadawane pytania dla graczy","description":"Często zadawane pytania dla graczy i administratorów serwerów dotyczące Fabric.","files":[]},"headers":[],"relativePath":"pl_pl/1.21.4/players/faq.md","filePath":"versions/1.21.4/translated/pl_pl/players/faq.md","lastUpdated":1760721669000}`);var a={name:`pl_pl/1.21.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Często zadawane pytania dla graczy <a class="header-anchor" href="#h1" aria-label="Permalink to “Często zadawane pytania dla graczy”">​</a></h1><p>Istnieje wiele często zadawanych pytań, więc zebraliśmy je tutaj w listę.</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Jakie wersje Minecrafta obsługuje Fabric? <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Jakie wersje Minecrafta obsługuje Fabric?”">​</a></h2><p>Oficjalnie, Fabric obsługuje wszystkie wersje Minecraft począwszy od snapshota <code>18w43b</code> i nowsze oraz od wersji <code>1.14</code> i nowsze.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">Skąd mogę pobrać mody do Fabric? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “Skąd mogę pobrać mody do Fabric?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Upewniaj się zawsze czy mody pochodzą z wiarygodnego źródła. Po więcej informacji sprawdź przewodnik na temat <a href="./finding-mods">znajdowania wiarygodnych modów</a>.</p></div><p>Większość twórców publikuje swoje mody na <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> i CurseForge, niektórzy mogą jednak zdecydować się na opublikowanie ich na swojej własnej stronie internetowej lub innych platformach, takich jak repozytorium GitHub.</p><h2 id="where-can-i-find-premade-fabric-modpacks" tabindex="-1">Gdzie mogę znaleźć gotowe paczki modów dla Fabric? <a class="header-anchor" href="#where-can-i-find-premade-fabric-modpacks" aria-label="Permalink to “Gdzie mogę znaleźć gotowe paczki modów dla Fabric?”">​</a></h2><p>Gotowe paczki modów dla Fabric znajdziesz na różnych platformach, takich jak:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks%5C&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};